declare @operation nvarchar(500) set  @operation='DIMMABLE GRADABLE'
update TM_PIT_Product_Instance
set pit_prd_info.modify('replace value of (/PropertyList/Propety[@PropGuid="6a98b2f0-2cd0-4861-afd5-e26881923291"]/@PropValue)[1] with sql:variable("@operation")')
where pit_id in 
(
select pit_id from TM_PIT_Product_Instance
where pit_ref like '%0g%'
)

declare @tempcolor nvarchar(500) set  @tempcolor='2700/6500, 0-10VK'
update TM_PIT_Product_Instance
set pit_prd_info.modify('replace value of (/PropertyList/Propety[@PropGuid="b692db5d-6530-4672-814b-5cb74bc2fe0d"]/@PropValue)[1] with sql:variable("@tempcolor")')
where pit_id in 
(
select pit_id from TM_PIT_Product_Instance
where pit_ref like '%0g%'
)




delete from TM_PIT_Product_Instance
where pit_ref like '%0g%' 
and pit_id not in
(select pit_id from TM_PIT_Product_Instance
where pit_ref like '%60g%')

